enum WalletError: Error, LocalizedError {
    case keyNotFound
    case keychain(OSStatus)
    case invalidKey
    case invalidSignature
    case invalidHex
    case rpcURLMissing
    case rpc(String)
    case rlp(String)
    case crypto(String)

    var errorDescription: String? {
        switch self {
        case .keyNotFound: return "Key not found"
        case .keychain(let s): return "Keychain error: \(s)"
        case .invalidKey: return "Invalid key"
        case .invalidSignature: return "Invalid signature"
        case .invalidHex: return "Invalid hex"
        case .rpcURLMissing: return "Missing RPC URL"
        case .rpc(let m): return "RPC: \(m)"
        case .rlp(let m): return "RLP: \(m)"
        case .crypto(let m): return "Crypto: \(m)"
        }
    }
}

