final class EthereumRPCClient {
    var url: URL?

    private struct RPCRequest<T: Encodable>: Encodable {
        let jsonrpc: String = "2.0"
        let id: Int = 1
        let method: String
        let params: T
    }
    private struct RPCResponse<R: Decodable>: Decodable {
        let jsonrpc: String?
        let id: Int?
        let result: R?
        let error: RPCError?
    }
    private struct RPCError: Decodable {
        let code: Int?
        let message: String?
        let data: String?
    }

    func getBalance(address: String) async throws -> String {
        let params = [address, "latest"]
        return try await call(method: "eth_getBalance", params: params)
    }

    func getTransactionCount(address: String) async throws -> Ethereum.Quantity {
        let params = [address, "pending"]
        let hex: String = try await call(method: "eth_getTransactionCount", params: params)
        return Ethereum.Quantity(hex: hex)
    }

    func sendRawTransaction(rawTx0x: String) async throws -> String {
        let params = [rawTx0x]
        let txHash: String = try await call(method: "eth_sendRawTransaction", params: params)
        return txHash
    }

    private func call<P: Encodable, R: Decodable>(method: String, params: P) async throws -> R {
        guard let url else { throw WalletError.rpcURLMissing }
        var req = URLRequest(url: url)
        req.httpMethod = "POST"
        req.setValue("application/json", forHTTPHeaderField: "Content-Type")
        req.timeoutInterval = 30

        let encoder = JSONEncoder()
        let body = try encoder.encode(RPCRequest(method: method, params: params))
        req.httpBody = body

        let (data, resp) = try await URLSession.shared.data(for: req)
        if let http = resp as? HTTPURLResponse, !(200...299).contains(http.statusCode) {
            throw WalletError.rpc("HTTP \(http.statusCode)")
        }

        let decoder = JSONDecoder()
        let decoded = try decoder.decode(RPCResponse<R>.self, from: data)
        if let err = decoded.error {
            throw WalletError.rpc("\(err.message ?? "Unknown")")
        }
        guard let result = decoded.result else {
            throw WalletError.rpc("No result")
        }
        return result
    }
}

enum Ethereum {
    struct Quantity: Equatable {
        var value: Data

        init(_ uint: UInt64) {
            self.value = Ethereum.bigEndianBytes(uint)
        }
        init(hex: String) throws {
            self.value = try Data(hexString: hex.strip0x())
            self.value = self.value.trimLeadingZeros()
            if self.value.isEmpty { self.value = Data() }
        }
        func hex0x() -> String {
            if value.isEmpty { return "0x0" }
            return "0x" + value.trimLeadingZeros().hexString.lowercased()
        }
    }

    struct Address: Equatable {
        let data20: Data
        init(hex: String) throws {
            let d = try Data(hexString: hex.strip0x())
            guard d.count == 20 else { throw WalletError.crypto("Address must be 20 bytes") }
            self.data20 = d
        }
    }

    struct Secp256k1Signature {
        let r: Data
        let s: Data
        let v: UInt8
        func toHexString0x() -> String {
            "0x" + r.leftPad(to: 32).hexString + s.leftPad(to: 32).hexString + String(format: "%02x", v)
        }
    }

    struct LegacyTx {
        let nonce: Quantity
        let gasPrice: Quantity
        let gasLimit: Quantity
        let to: Address
        let value: Quantity
        let data: Data
    }

    struct SignedLegacyTx {
        let tx: LegacyTx
        let sig: Secp256k1Signature
        let chainId: Int
    }

    static func legacySighash(tx: LegacyTx, chainId: Int) -> Data {
        let rlp = RLP.encode([
            rlpQuantity(tx.nonce),
            rlpQuantity(tx.gasPrice),
            rlpQuantity(tx.gasLimit),
            RLP.encode(tx.to.data20),
            rlpQuantity(tx.value),
            RLP.encode(tx.data),
            rlpInt(chainId),
            RLP.encode(Data()),
            RLP.encode(Data())
        ])
        return keccak256(rlp)
    }

    static func encodeSignedLegacyTx(_ signed: SignedLegacyTx) -> Data {
        let vInt = signed.sigV(chainId: signed.chainId)
        return RLP.encode([
            rlpQuantity(signed.tx.nonce),
            rlpQuantity(signed.tx.gasPrice),
            rlpQuantity(signed.tx.gasLimit),
            RLP.encode(signed.tx.to.data20),
            rlpQuantity(signed.tx.value),
            RLP.encode(signed.tx.data),
            rlpInt(vInt),
            RLP.encode(signed.sig.r.leftPad(to: 32).trimLeadingZeros()),
            RLP.encode(signed.sig.s.leftPad(to: 32).trimLeadingZeros())
        ])
    }

    static func keccak256(_ data: Data) -> Data {
        Keccak256.hash(data)
    }

    static func address(fromUncompressedPublicKey pub65: Data) -> String {
        let pub = pub65.count == 65 && pub65.first == 0x04 ? pub65.dropFirst() : pub65[0..<64]
        let hash = keccak256(Data(pub))
        let addr = hash.suffix(20)
        return toChecksumAddress("0x" + addr.hexString)
    }

    static func toChecksumAddress(_ address0xLowerOrAny: String) -> String {
        let addr = address0xLowerOrAny.strip0x().lowercased()
        let hash = keccak256(Data(addr.utf8)).hexString
        var out = "0x"
        for (i, c) in addr.enumerated() {
            let h = Int(String(hash[hash.index(hash.startIndex, offsetBy: i)]), radix: 16) ?? 0
            if h >= 8 {
                out.append(String(c).uppercased())
            } else {
                out.append(c)
            }
        }
        return out
    }

    static func recoverableRecId(digest32: Data, r: Data, s: Data, uncompressedPubKey: Data) throws -> Int {
        for recId in 0..<2 {
            if let recovered = Secp256k1Recover.recoverPublicKey(digest32: digest32, r: r, s: s, recId: recId) {
                if recovered == uncompressedPubKey { return recId }
            }
        }
        return 0
    }

    private static func rlpQuantity(_ q: Quantity) -> Data {
        let v = q.value.trimLeadingZeros()
        return RLP.encode(v)
    }

    private static func rlpInt(_ i: Int) -> Data {
        if i == 0 { return RLP.encode(Data()) }
        let d = bigEndianBytes(UInt64(i)).trimLeadingZeros()
        return RLP.encode(d)
    }

    private static func bigEndianBytes(_ v: UInt64) -> Data {
        var x = v
        var bytes = [UInt8](repeating: 0, count: 8)
        for i in (0..<8).reversed() {
            bytes[i] = UInt8(x & 0xff)
            x >>= 8
        }
        return Data(bytes).trimLeadingZeros()
    }
}

