enum ASN1 {
    static func parseEcdsaDerSignature(_ der: Data) throws -> (r: Data, s: Data) {
        var i = 0
        func readByte() throws -> UInt8 {
            guard i < der.count else { throw WalletError.crypto("ASN1 out of range") }
            let b = der[i]
            i += 1
            return b
        }
        func readLength() throws -> Int {
            let first = try readByte()
            if first & 0x80 == 0 { return Int(first) }
            let n = Int(first & 0x7f)
            guard n > 0 && n <= 2 else { throw WalletError.crypto("ASN1 length too long") }
            var len = 0
            for _ in 0..<n {
                len = (len << 8) | Int(try readByte())
            }
            return len
        }
        func readInteger() throws -> Data {
            let tag = try readByte()
            guard tag == 0x02 else { throw WalletError.crypto("ASN1 expected INTEGER") }
            let len = try readLength()
            guard i + len <= der.count else { throw WalletError.crypto("ASN1 integer overflow") }
            let bytes = der.subdata(in: i..<(i+len))
            i += len
            return bytes.trimLeadingZeros()
        }

        let seqTag = try readByte()
        guard seqTag == 0x30 else { throw WalletError.crypto("ASN1 expected SEQUENCE") }
        _ = try readLength()
        let r = try readInteger()
        let s = try readInteger()
        return (r, s)
    }
}

enum RLP {
    static func encode(_ bytes: Data) -> Data {
        if bytes.count == 1, let b = bytes.first, b <= 0x7f { return bytes }
        return encodeLength(bytes.count, offset: 0x80) + bytes
    }

    static func encode(_ list: [Data]) -> Data {
        let payload = list.reduce(Data(), +)
        return encodeLength(payload.count, offset: 0xc0) + payload
    }

    private static func encodeLength(_ length: Int, offset: UInt8) -> Data {
        if length < 56 {
            return Data([offset + UInt8(length)])
        } else {
            let lenBytes = intToMinimalBE(length)
            return Data([offset + 55 + UInt8(lenBytes.count)]) + lenBytes
        }
    }

    private static func intToMinimalBE(_ v: Int) -> Data {
        var x = v
        var bytes = [UInt8]()
        while x > 0 {
            bytes.append(UInt8(x & 0xff))
            x >>= 8
        }
        return Data(bytes.reversed())
    }
}

enum Keccak256 {
    static func hash(_ data: Data) -> Data {
        var ctx = KeccakState()
        ctx.absorb(data)
        return ctx.squeeze(32)
    }

    private struct KeccakState {
        private var a = [UInt64](repeating: 0, count: 25)
        private let rate = 136
        private let delim: UInt8 = 0x01

        mutating func absorb(_ data: Data) {
            var offset = 0
            while offset < data.count {
                let block = min(rate, data.count - offset)
                for i in 0..<block {
                    let idx = i >> 3
                    let shift = UInt64((i & 7) * 8)
                    a[idx] ^= UInt64(data[offset + i]) << shift
                }
                offset += block
                if block == rate {
                    keccakF()
                } else {
                    var pad = Data(repeating: 0, count: rate - block)
                    pad[0] = delim
                    pad[rate - block - 1] |= 0x80
                    for i in 0..<pad.count {
                        let idx = (block + i) >> 3
                        let shift = UInt64(((block + i) & 7) * 8)
                        a[idx] ^= UInt64(pad[i]) << shift
                    }
                    keccakF()
                    return
                }
            }
            var pad = Data(repeating: 0, count: rate)
            pad[0] = delim
            pad[rate - 1] |= 0x80
            for i in 0..<rate {
                let idx = i >> 3
                let shift = UInt64((i & 7) * 8)
                a[idx] ^= UInt64(pad[i]) << shift
            }
            keccakF()
        }

        mutating func squeeze(_ outLen: Int) -> Data {
            var out = Data()
            while out.count < outLen {
                for i in 0..<rate {
                    let idx = i >> 3
                    let shift = UInt64((i & 7) * 8)
                    out.append(UInt8((a[idx] >> shift) & 0xff))
                    if out.count == outLen { return out }
                }
                keccakF()
            }
            return out
        }

