                }

                var b = [UInt64](repeating: 0, count: 25)
                for i in 0..<25 {
                    b[piln[i]] = rotl(a[i], r[i])
                }

                for y in 0..<5 {
                    for x in 0..<5 {
                        a[x + 5*y] = b[x + 5*y] ^ ((~b[((x+1)%5) + 5*y]) & b[((x+2)%5) + 5*y])
                    }
                }

                a[0] ^= rc[round]
            }
        }

        private func rotl(_ x: UInt64, _ n: Int) -> UInt64 {
            (x << UInt64(n)) | (x >> UInt64(64 - n))
        }
    }
}

