extension Data {
    init(hexString: String) throws {
        let s = hexString.count % 2 == 0 ? hexString : "0" + hexString
        var out = Data()
        out.reserveCapacity(s.count / 2)
        var i = s.startIndex
        while i < s.endIndex {
            let j = s.index(i, offsetBy: 2)
            let byteStr = s[i..<j]
            guard let b = UInt8(byteStr, radix: 16) else { throw WalletError.invalidHex }
            out.append(b)
            i = j
        }
        self = out
    }

    var hexString: String {
        map { String(format: "%02x", $0) }.joined()
    }

    func trimLeadingZeros() -> Data {
        var idx = startIndex
        while idx < endIndex && self[idx] == 0 { idx = index(after: idx) }
        return self[idx..<endIndex]
    }

    func leftPad(to size: Int) -> Data {
        if count >= size { return self }
        return Data(repeating: 0, count: size - count) + self
    }
}

extension String {
    func strip0x() -> String {
        if lowercased().hasPrefix("0x") { return String(dropFirst(2)) }
        return self
    }
}